def _wait_until(predicate, timeout_seconds: float = 1.0) -> bool:
    deadline = time.monotonic() + timeout_seconds
    while time.monotonic() < deadline:
        if predicate():
            return True
        time.sleep(0.01)
    return predicate()


def _base_manifest(plugin_id: str, runtime: dict, database: dict | None = None) -> dict:
    manifest = {
